    val repliesFlow = flowOf(PagingData.empty<Post>())
    composeRule.setContent {
        TestTheme {
            val replies = repliesFlow.collectAsLazyPagingItems()
            PostDetailContent(
                post = post,
                reactionGroups = emptyList(),
