1	import { assert } from "@std/assert";
2	import { isActor } from "@fedify/vocab";
3	import { desc, eq } from "drizzle-orm";
4	import {
5	  getAvatarUrl,
6	  persistActor,
7	  recommendActors,
8	} from "@hackerspub/models/actor";
9	import { block, unblock } from "@hackerspub/models/blocking";
10	import { renderCustomEmojis } from "@hackerspub/models/emoji";
11	import {
12	  follow,
13	  removeFollower as removeFollowerModel,
14	  unfollow,
15	} from "@hackerspub/models/following";
16	import { getPostVisibilityFilter } from "@hackerspub/models/post";
17	import type { Actor as ActorModel } from "@hackerspub/models/schema";
18	import { validateUuid } from "@hackerspub/models/uuid";
19	import { drizzleConnectionHelpers } from "@pothos/plugin-drizzle";
20	import { assertNever } from "@std/assert/unstable-never";
21	import { escape } from "@std/html/entities";
22	import xss from "xss";
23	import { builder } from "./builder.ts";
24	import { InvalidInputError } from "./error.ts";
25	import { Article, Note, Post, Question } from "./post.ts";
26	import { NotAuthenticatedError } from "./session.ts";
27	
28	export const ActorType = builder.enumType("ActorType", {
29	  values: [
30	    "APPLICATION",
31	    "GROUP",
32	    "ORGANIZATION",
33	    "PERSON",
34	    "SERVICE",
35	  ] as const,
36	});
37	
38	export const Actor = builder.drizzleNode("actorTable", {
39	  name: "Actor",
40	  id: {
41	    column: (actor) => actor.id,
42	  },
43	  fields: (t) => ({
44	    uuid: t.expose("id", { type: "UUID" }),
45	    iri: t.field({
46	      type: "URL",
47	      select: {
48	        columns: { iri: true, accountId: true },
49	      },
50	      resolve(actor, _, ctx) {
51	        return actor.accountId == null
52	          ? new URL(actor.iri)
53	          : ctx.fedCtx.getActorUri(actor.accountId);
54	      },
55	    }),
56	    type: t.field({
57	      type: ActorType,
58	      select: {
59	        columns: { type: true },
60	      },
61	      resolve(actor) {
62	        return actor.type === "Application"
63	          ? "APPLICATION"
64	          : actor.type === "Group"
65	          ? "GROUP"
66	          : actor.type === "Organization"
67	          ? "ORGANIZATION"
68	          : actor.type === "Person"
69	          ? "PERSON"
70	          : actor.type === "Service"
71	          ? "SERVICE"
72	          : assertNever(
73	            actor.type,
74	            `Unknown value in \`Actor.type\`: "${actor.type}"`,
75	          );
76	      },
77	    }),
78	    local: t.boolean({
79	      select: {
80	        columns: { accountId: true },
81	      },
82	      resolve(actor) {
83	        return actor.accountId != null;
84	      },
85	    }),
86	    username: t.exposeString("username"),
87	    instanceHost: t.exposeString("instanceHost"),
88	    handleHost: t.exposeString("handleHost"),
